```c
int copy_struct_from_user(void *dst, size_t ksize, const void __user *src, size_t usize) {
	size_t size = min(ksize, usize);
	size_t rest = max(ksize, usize) - size;

	/* ... */
	/* Deal with trailing bytes. */
	if (usize < ksize) {
